17	
18	    virtual void from_ast(const common_peg_ast_arena & arena, const common_peg_parse_result & result);
19	    virtual void map(const common_peg_ast_node & node);
20	  protected:
21	    virtual std::string normalize_container_value(const std::string & input);
22	  private:
23	      // Tool call handling state
24	      std::optional<common_chat_tool_call> pending_tool_call;  // Tool call waiting for name
25	      common_chat_tool_call *              current_tool          = nullptr;
26	      int                                  arg_count             = 0;
27	      bool                                 closing_quote_pending = false;
28	      std::string                          args_buffer;  // Buffer to delay arguments until tool name is known
29	
30	      // Returns a reference to the active argument destination string.
31	      // Before tool_name is known, writes go to args_buffer; after, to current_tool->arguments.
32	      std::string & args_target();
33	};
