45	class common_chat_peg_builder : public common_peg_parser_builder {
46	  public:
47	    // Tag constants (from former common_chat_peg_base_builder)
48	    static constexpr const char * REASONING_BLOCK = "reasoning-block";
49	    static constexpr const char * REASONING       = "reasoning";
50	    static constexpr const char * CONTENT         = "content";
51	
52	    // Tag constants
53	    static constexpr const char * TOOL           = "tool";
54	    static constexpr const char * TOOL_OPEN      = "tool-open";
55	    static constexpr const char * TOOL_CLOSE     = "tool-close";
56	    static constexpr const char * TOOL_ID        = "tool-id";
57	    static constexpr const char * TOOL_NAME      = "tool-name";
58	    static constexpr const char * TOOL_ARGS      = "tool-args";
59	    static constexpr const char * TOOL_ARG       = "tool-arg";
60	    static constexpr const char * TOOL_ARG_OPEN  = "tool-arg-open";
61	    static constexpr const char * TOOL_ARG_CLOSE = "tool-arg-close";
62	    static constexpr const char * TOOL_ARG_NAME         = "tool-arg-name";
63	    static constexpr const char * TOOL_ARG_VALUE        = "tool-arg-value";
64	    static constexpr const char * TOOL_ARG_STRING_VALUE = "tool-arg-string-value";  // For schema-declared string types
65	
66	    // Low-level tag methods (from former common_chat_peg_base_builder)
67	    common_peg_parser reasoning_block(const common_peg_parser & p) { return tag(REASONING_BLOCK, p); }
68	
69	    common_peg_parser reasoning(const common_peg_parser & p) { return tag(REASONING, p); }
70	
71	    common_peg_parser content(const common_peg_parser & p) { return tag(CONTENT, p); }
72	
73	    common_peg_parser tag_with_safe_content(const std::string &       tag_name,
74	                        const std::string &       marker,
75	                        const common_peg_parser & p);
76	
77	    // Low-level tag methods
78	    common_peg_parser tool(const common_peg_parser & p) { return tag(TOOL, p); }
79	    common_peg_parser tool_open(const common_peg_parser & p) { return atomic(tag(TOOL_OPEN, p)); }
80	    common_peg_parser tool_close(const common_peg_parser & p) { return atomic(tag(TOOL_CLOSE, p)); }
81	    common_peg_parser tool_id(const common_peg_parser & p) { return atomic(tag(TOOL_ID, p)); }
82	    common_peg_parser tool_name(const common_peg_parser & p) { return atomic(tag(TOOL_NAME, p)); }
83	    common_peg_parser tool_args(const common_peg_parser & p) { return tag(TOOL_ARGS, p); }
84	    common_peg_parser tool_arg(const common_peg_parser & p) { return tag(TOOL_ARG, p); }
85	    common_peg_parser tool_arg_open(const common_peg_parser & p) { return atomic(tag(TOOL_ARG_OPEN, p)); }
86	    common_peg_parser tool_arg_close(const common_peg_parser & p) { return atomic(tag(TOOL_ARG_CLOSE, p)); }
87	    common_peg_parser tool_arg_name(const common_peg_parser & p) { return atomic(tag(TOOL_ARG_NAME, p)); }
88	    common_peg_parser tool_arg_value(const common_peg_parser & p) { return tag(TOOL_ARG_VALUE, p); }
89	
90	    // Use for schema-declared string types - won't be treated as potential JSON container
91	    common_peg_parser tool_arg_string_value(const common_peg_parser & p) { return tag(TOOL_ARG_STRING_VALUE, p); }
92	    common_peg_parser tool_arg_json_value(const common_peg_parser & p) { return atomic(tag(TOOL_ARG_VALUE, p)); }
93	
94	
95	    // Return a parser that parses the prefix of a string, up to a given delimiter.
96	    common_peg_parser prefix(const std::string & s, const std::string & delimiter = {});
97	
98	    // Legacy-compatible helper for building standard JSON tool calls
99	    // Used by tests and manual parsers
100	    // name_key/args_key: JSON key names for function name and arguments
101	    //   Empty or "name"/"arguments" will accept both common variations
102	    //   Supports dot notation for nested objects (e.g., "function.name")
103	    // array_wrapped: if true, tool calls are wrapped in JSON array [...]
104	    // function_is_key: if true, function name is the JSON key (e.g., {"func_name": {...}})
105	    // call_id_key: JSON key for string call ID (e.g., "id")
106	    // gen_call_id_key: JSON key for generated integer call ID (e.g., "tool_call_id")
107	    // parameters_order: order in which JSON fields should be parsed
108	    common_peg_parser standard_json_tools(const std::string &              section_start,
109	                                          const std::string &              section_end,
110	                                          const nlohmann::ordered_json &   tools,
111	                                          bool                             parallel_tool_calls,
112	                                          bool                             force_tool_calls,
113	                                          const std::string &              name_key = "",
114	                                          const std::string &              args_key = "",
115	                                          bool                             array_wrapped = false,
116	                                          bool                             function_is_key = false,
117	                                          const std::string &              call_id_key = "",
118	                                          const std::string &              gen_call_id_key = "",
119	                                          const std::vector<std::string> & parameters_order = {});
120	
121	    // Legacy-compatible helper for building XML/tagged style tool calls
122	    // Used by tests and manual parsers
123	    common_peg_parser standard_constructed_tools(const std::map<std::string, std::string> & markers,
124	                                                 const nlohmann::ordered_json &             tools,
125	                                                 bool                                       parallel_tool_calls,
126	                                                 bool                                       force_tool_calls);
127	
128	    // Helper for Python-style function call format: name(arg1="value1", arg2=123)
129	    // Used by LFM2 and similar templates
130	    common_peg_parser python_style_tool_calls(const nlohmann::ordered_json & tools,
131	                                              bool                           parallel_tool_calls);
132	
133	  private:
134	    // Implementation helpers for standard_json_tools — one per JSON tool call layout mode
135	    common_peg_parser build_json_tools_function_is_key(const nlohmann::ordered_json & tools,
136	                                                       const std::string &            args_key,
137	                                                       const std::string &            effective_args_key,
138	                                                       const std::string &            call_id_key,
139	                                                       const std::string &            gen_call_id_key);
140	
141	    common_peg_parser build_json_tools_nested_keys(const nlohmann::ordered_json & tools,
142	                                                   const std::string &            effective_name_key,
143	                                                   const std::string &            effective_args_key,
144	                                                   const std::string &            call_id_key,
145	                                                   const std::string &            gen_call_id_key);
146	
147	    common_peg_parser build_json_tools_flat_keys(const nlohmann::ordered_json &   tools,
148	                                                 const std::string &              effective_name_key,
149	                                                 const std::string &              effective_args_key,
150	                                                 const std::string &              call_id_key,
151	                                                 const std::string &              gen_call_id_key,
152	                                                 const std::vector<std::string> & parameters_order);
153	};
154	
155	inline common_peg_arena build_chat_peg_parser(
156	  const std::function<common_peg_parser(common_chat_peg_builder & builder)> & fn) {
157	  common_chat_peg_builder builder;
158	  builder.set_root(fn(builder));
159	  return builder.build();
160	}
