173	    } else if (tmpl_contains("<|start_header_id|>") && tmpl_contains("<|end_header_id|>")) {
174	        return LLM_CHAT_TEMPLATE_LLAMA_3;
175	    } else if (tmpl_contains("[gMASK]sop")) {
