87	llm_chat_template llm_chat_detect_template(const std::string & tmpl) {
88	    try {
89	        return llm_chat_template_from_str(tmpl);
90	    } catch (const std::out_of_range &) {
91	        // ignore
92	    }
93	
94	    auto tmpl_contains = [&tmpl](const char * haystack) -> bool {
95	        return tmpl.find(haystack) != std::string::npos;
96	    };
97	    if (tmpl_contains("<|im_start|>")) {
98	        return tmpl_contains("<|im_sep|>")
99	            ? LLM_CHAT_TEMPLATE_PHI_4
100	            : tmpl_contains("<end_of_utterance>")
101	                ? LLM_CHAT_TEMPLATE_SMOLVLM // SmolVLM uses <|im_start|> as BOS, but it is NOT chatml
102	                : LLM_CHAT_TEMPLATE_CHATML;
103	    } else if (tmpl.find("mistral") == 0 || tmpl_contains("[INST]")) {
104	        if (tmpl_contains("[SYSTEM_PROMPT]")) {
105	            return LLM_CHAT_TEMPLATE_MISTRAL_V7;
106	        } else if (
107	            // catches official 'v1' template
108	            tmpl_contains("' [INST] ' + system_message")
109	            // catches official 'v3' and 'v3-tekken' templates
110	            || tmpl_contains("[AVAILABLE_TOOLS]")
111	        ) {
112	            // Official mistral 'v1', 'v3' and 'v3-tekken' templates
113	            // See: https://github.com/mistralai/cookbook/blob/main/concept-deep-dive/tokenization/chat_templates.md
114	            // See: https://github.com/mistralai/cookbook/blob/main/concept-deep-dive/tokenization/templates.md
115	            if (tmpl_contains(" [INST]")) {
116	                return LLM_CHAT_TEMPLATE_MISTRAL_V1;
117	            } else if (tmpl_contains("\"[INST]\"")) {
118	                return LLM_CHAT_TEMPLATE_MISTRAL_V3_TEKKEN;
119	            }
120	            return LLM_CHAT_TEMPLATE_MISTRAL_V3;
121	        } else {
122	            // llama2 template and its variants
123	            // [variant] support system message
124	            // See: https://huggingface.co/blog/llama2#how-to-prompt-llama-2
125	            bool support_system_message = tmpl_contains("<<SYS>>");
126	            bool add_bos_inside_history = tmpl_contains("bos_token + '[INST]");
127	            bool strip_message = tmpl_contains("content.strip()");
128	            if (strip_message) {
129	                return LLM_CHAT_TEMPLATE_LLAMA_2_SYS_STRIP;
130	            } else if (add_bos_inside_history) {
131	                return LLM_CHAT_TEMPLATE_LLAMA_2_SYS_BOS;
132	            } else if (support_system_message) {
133	                return LLM_CHAT_TEMPLATE_LLAMA_2_SYS;
134	            } else {
135	                return LLM_CHAT_TEMPLATE_LLAMA_2;
136	            }
137	        }
138	    } else if (tmpl_contains("<|assistant|>") && tmpl_contains("<|end|>")) {
139	        return LLM_CHAT_TEMPLATE_PHI_3;
140	    } else if (tmpl_contains("[gMASK]<sop>")) {
141	        return LLM_CHAT_TEMPLATE_CHATGLM_4;
142	    } else if (tmpl_contains("<|assistant|>") && tmpl_contains("<|user|>")) {
143	        if (tmpl_contains("<|tool_declare|>")) {
144	            return LLM_CHAT_TEMPLATE_EXAONE_MOE;
145	        }
146	        return tmpl_contains("</s>") ? LLM_CHAT_TEMPLATE_FALCON_3 : LLM_CHAT_TEMPLATE_GLMEDGE;
147	    } else if (tmpl_contains("<|{{ item['role'] }}|>") && tmpl_contains("<|begin_of_image|>")) {
148	        return LLM_CHAT_TEMPLATE_GLMEDGE;
149	    } else if (tmpl_contains("<|user|>") && tmpl_contains("<|endoftext|>")) {
150	        return LLM_CHAT_TEMPLATE_ZEPHYR;
151	    } else if (tmpl_contains("bos_token + message['role']")) {
152	        return LLM_CHAT_TEMPLATE_MONARCH;
153	    } else if (tmpl_contains("<start_of_turn>")) {
154	        return LLM_CHAT_TEMPLATE_GEMMA;
155	    } else if (tmpl_contains("'\\n\\nAssistant: ' + eos_token")) {
156	        // OrionStarAI/Orion-14B-Chat
157	        return LLM_CHAT_TEMPLATE_ORION;
158	    } else if (tmpl_contains("GPT4 Correct ")) {
159	        // openchat/openchat-3.5-0106
160	        return LLM_CHAT_TEMPLATE_OPENCHAT;
161	    } else if (tmpl_contains("USER: ") && tmpl_contains("ASSISTANT: ")) {
